/// Executor for ShareCreation flow
pub struct ShareCreationFlowExecutor<H: ShareCreationStepHandler>(FlowExecutor<H>);

impl<H: ShareCreationStepHandler + Send + Sync + 'static> ShareCreationFlowExecutor<H> {
    /// Create a new flow executor
    pub fn new(handler: Arc<H>) -> Self {
        Self(FlowExecutor::new(handler))
    }

    /// Start a new flow instance
    pub fn start(&self, instance_id: impl Into<String>) -> ShareCreationFlowInstance {
        self.0.start(instance_id, ShareCreationFlowStep::ValidateFile)
    }

    /// Execute the current step
    pub async fn execute_step(&self, instance: &mut ShareCreationFlowInstance) -> Result<(), FlowError> {
        let current_step = match instance.current_step {
            Some(step) => step,
            None => return Err(FlowError::NoCurrentStep),
        };

        let next_step = match current_step {
            ShareCreationFlowStep::ValidateFile => {
                self.0.handler.handle_validate_file(instance).await?
            }
            ShareCreationFlowStep::CheckSharePermission => {
                let next = self.0.handler.evaluate_check_share_permission(instance).await?;
                Some(next)
            }
            ShareCreationFlowStep::CheckManagePermission => {
                self.0.handler.handle_check_manage_permission(instance).await?
            }
            ShareCreationFlowStep::CheckShareType => {
                let next = self.0.handler.evaluate_check_share_type(instance).await?;
                Some(next)
            }
            ShareCreationFlowStep::ValidatePublicShare => {
                self.0.handler.handle_validate_public_share(instance).await?
            }
            ShareCreationFlowStep::ValidateUserShare => {
                self.0.handler.handle_validate_user_share(instance).await?
            }
            ShareCreationFlowStep::ValidateEmailShare => {
                self.0.handler.handle_validate_email_share(instance).await?
            }
            ShareCreationFlowStep::CheckExistingShare => {
                self.0.handler.handle_check_existing_share(instance).await?
            }
            ShareCreationFlowStep::UpdateExistingShare => {
                self.0.handler.handle_update_existing_share(instance).await?
            }
            ShareCreationFlowStep::CreateShareRecord => {
                self.0.handler.handle_create_share_record(instance).await?
            }
            ShareCreationFlowStep::GenerateShareUrl => {
                self.0.handler.handle_generate_share_url(instance).await?
            }
            ShareCreationFlowStep::DetermineNotification => {
                let next = self.0.handler.evaluate_determine_notification(instance).await?;
                Some(next)
            }
            ShareCreationFlowStep::NotifyUser => {
                self.0.handler.handle_notify_user(instance).await?
            }
            ShareCreationFlowStep::SendEmailInvitation => {
                self.0.handler.handle_send_email_invitation(instance).await?
            }
            ShareCreationFlowStep::LogShare => {
                self.0.handler.handle_log_share(instance).await?
            }
            ShareCreationFlowStep::Complete => {
                self.0.handler.handle_complete(instance).await?;
                None // Terminal step
            }
            ShareCreationFlowStep::FileNotFound => {
                self.0.handler.handle_file_not_found(instance).await?;
                None // Terminal step
            }
            ShareCreationFlowStep::PermissionDenied => {
                self.0.handler.handle_permission_denied(instance).await?
            }
            ShareCreationFlowStep::FailedPermission => {
                self.0.handler.handle_failed_permission(instance).await?;
                None // Terminal step
            }
            ShareCreationFlowStep::PublicSharingDisabled => {
                self.0.handler.handle_public_sharing_disabled(instance).await?;
                None // Terminal step
            }
            ShareCreationFlowStep::UserNotFound => {
                self.0.handler.handle_user_not_found(instance).await?;
                None // Terminal step
            }
            ShareCreationFlowStep::InvalidConfig => {
                self.0.handler.handle_invalid_config(instance).await?;
                None // Terminal step
            }
        };

        // Mark current step as completed
        instance.completed_steps.push(current_step);

        // Move to next step
        match next_step {
            Some(next) => {
                instance.current_step = Some(next);
            }
            None => {
                instance.current_step = None;
                instance.status = FlowStatus::Completed;
            }
        }

        instance.updated_at = chrono::Utc::now();
        Ok(())
    }

    /// Run the flow to completion
    pub async fn run(&self, instance: &mut ShareCreationFlowInstance) -> Result<(), FlowError> {
        while !instance.is_complete() && instance.status != FlowStatus::Waiting {
            self.execute_step(instance).await?;
        }
        Ok(())
    }

    /// Cancel the flow
    pub fn cancel(&self, instance: &mut ShareCreationFlowInstance) { self.0.cancel(instance) }

    /// Mark flow as failed
    pub fn fail(&self, instance: &mut ShareCreationFlowInstance, error: impl Into<String>) { self.0.fail(instance, error) }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_flow_instance_creation() {
        let instance = ShareCreationFlowInstance::new("test-1");
        assert_eq!(instance.id, "test-1");
        assert_eq!(instance.status, FlowStatus::Pending);
        assert!(!instance.is_complete());
    }

    #[test]
    fn test_flow_context() {
        let mut instance = ShareCreationFlowInstance::new("test-2");
        instance.set_context("key", serde_json::json!("value"));
        let value = instance.get_context("key");
        assert_eq!(value, Some(&serde_json::json!("value")));
    }

    #[test]
    fn test_flow_status_transitions() {
        let mut instance = ShareCreationFlowInstance::new("test-3");
        assert!(!instance.is_running());

        instance.status = FlowStatus::Running;
        assert!(instance.is_running());
        assert!(!instance.is_complete());

        instance.status = FlowStatus::Completed;
        assert!(instance.is_complete());
        assert!(!instance.is_running());
    }
}
